/**
 * CDP test for camera auto-detect flow on Vercel preview (dev branch).
 * Run: node scripts/test-camera-preview-cdp.mjs
 *
 * Bypasses Vercel deployment protection via x-vercel-protection-bypass header
 * (generated by `vercel curl`). The token is request-scoped, so we set it as
 * an extra header that applies to ALL requests via CDP.
 */
import CDP from 'chrome-remote-interface';
import fs from 'fs';

const PREVIEW_URL = 'https://flashmind-48v0bx7m4-alif-fakhrurrozy-6516s-projects.vercel.app';
const BYPASS_TOKEN = '[REDACTED-vercel-bypass]';
const LOGIN_EMAIL = 'rls-test@flash.com';
const LOGIN_PASSWORD = 'rlstest123';

async function main() {
  let client;
  let passed = 0;
  let failed = 0;
  const log = (label, ok, detail = '') => {
    console.log(`${ok ? '✓' : '✗'} ${label}${detail ? ': ' + detail : ''}`);
    ok ? passed++ : failed++;
  };

  try {
    client = await CDP();
    const { Page, Runtime, Network, Emulation } = client;
    await Promise.all([Page.enable(), Runtime.enable(), Network.enable()]);
    await Network.setCacheDisabled({ cacheDisabled: true });
    // ponytail: apply bypass to ALL requests including page navigation + fetch
    await Network.setExtraHTTPHeaders({ headers: { 'x-vercel-protection-bypass': BYPASS_TOKEN } });
    // ponytail: emulate mobile device so capture="environment" opens camera (not file picker)
    await Emulation.setDeviceMetricsOverride({
      width: 390, height: 844, deviceScaleFactor: 3, mobile: true,
    });
    await Emulation.setUserAgentOverride({
      userAgent: 'Mozilla/5.0 (iPhone; CPU iPhone OS 17_0 like Mac OS X) AppleWebKit/605.1.15 (KHTML, like Gecko) Version/17.0 Mobile/15E148 Safari/604.1',
    });

    // ===== Test 1: Verify preview bundle has camera fix code =====
    console.log('\n=== Test 1: Preview bundle has camera auto-detect ===');
    await Page.navigate({ url: PREVIEW_URL });
    await Page.loadEventFired();
    await new Promise(r => setTimeout(r, 3000));

    // Verify we got the actual app (not Vercel SSO login page)
    const title = await Runtime.evaluate({ expression: 'document.title', returnByValue: true });
    log('Page title is FlashMind (not SSO)', title.result.value === 'FlashMind',
      `title="${title.result.value}"`);

    const bundleUrl = await Runtime.evaluate({
      expression: `(() => {
        const scripts = Array.from(document.querySelectorAll('script[src*="index-"]'));
        return scripts[0]?.src || '';
      })()`,
      returnByValue: true,
    });
    log('Bundle detected', !!bundleUrl.result.value, bundleUrl.result.value.split('/').pop());

    // Extract bundle name + fetch source
    const bundleName = bundleUrl.result.value.split('/').pop();
    if (bundleName) {
      const srcCheck = await Runtime.evaluate({
        expression: `(async () => {
          const r = await fetch('/assets/${bundleName}');
          const text = await r.text();
          return {
            hasGetUserMedia: text.includes('getUserMedia'),
            hasCaptureEnv: text.includes('capture') && text.includes('environment'),
            hasCameraStatus: text.includes('cameraStatus') || text.includes("'checking'"),
            hasIdleOrAvailable: text.includes("'available'") || text.includes('"available"'),
            hasAiUploadHint: text.includes('ai-upload-hint'),
            hasKameraSiap: text.includes('Kamera siap') || text.includes('kamera siap'),
            hasMemintaIzin: text.includes('Meminta izin') || text.includes('meminta izin'),
            size: text.length,
          };
        })()`,
        awaitPromise: true, returnByValue: true,
      });
      const r = srcCheck.result.value;
      console.log(`  Bundle size: ${r.size} bytes`);
      log('Bundle has getUserMedia (auto-detect API)', r.hasGetUserMedia);
      log('Bundle has capture="environment" (camera)', r.hasCaptureEnv);
      log('Bundle has cameraStatus state', r.hasCameraStatus);
      log('Bundle has "available" state', r.hasIdleOrAvailable);
      log('Bundle has ai-upload-hint class', r.hasAiUploadHint);
      log('Bundle has "Kamera siap" hint', r.hasKameraSiap);
      log('Bundle has "Meminta izin" hint', r.hasMemintaIzin);
    }

    // ===== Test 2: Login + open editor + verify camera button states =====
    console.log('\n=== Test 2: Camera button states on preview ===');

    // Login
    const login = await Runtime.evaluate({
      expression: `(async () => { const r = await fetch('/api/auth/login', { method: 'POST', headers: {'Content-Type':'application/json'}, body: JSON.stringify({email:'${LOGIN_EMAIL}', password:'${LOGIN_PASSWORD}'}), credentials:'include'}); return { ok: r.ok, status: r.status }; })()`,
      awaitPromise: true, returnByValue: true,
    });
    log('Login', login.result.value.ok, `status=${login.result.value.status}`);

    // Mock getUserMedia to control detection result
    await Runtime.evaluate({
      expression: `(() => {
        Object.defineProperty(navigator, 'mediaDevices', {
          configurable: true,
          value: {
            getUserMedia: async () => {
              const track = { stop: () => {} };
              return { getTracks: () => [track] };
            },
          },
        });
      })()`,
      returnByValue: true,
    });

    // Navigate to dashboard
    await Page.navigate({ url: PREVIEW_URL + '/app' });
    await Page.loadEventFired();
    await new Promise(r => setTimeout(r, 5000));

    // Verify dashboard rendered
    const dashCheck = await Runtime.evaluate({
      expression: `(() => {
        const header = document.querySelector('.dashboard-header-right');
        if (!header) return { found: false };
        const buttons = Array.from(header.querySelectorAll('button'));
        return {
          found: true,
          buttons: buttons.map(b => b.textContent.trim()),
        };
      })()`,
      returnByValue: true,
    });
    log('Dashboard header rendered', dashCheck.result.value.found);
    if (dashCheck.result.value.found) {
      console.log(`  Buttons: ${JSON.stringify(dashCheck.result.value.buttons)}`);
      const labels = dashCheck.result.value.buttons;
      log('Has "+ Kartu Baru" button', labels.some(l => l.includes('Kartu Baru')));
      log('Does NOT have "Buat dengan AI" button', !labels.some(l => l.includes('Buat dengan AI') || l.includes('AI')));
    }

    // Open editor
    await Runtime.evaluate({
      expression: `(() => { const btn = Array.from(document.querySelectorAll('.dashboard-header-right button')).find(b => b.textContent.includes('Kartu Baru')); if (btn) btn.click(); })()`,
      returnByValue: true,
    });
    await new Promise(r => setTimeout(r, 2000));

    const modalCheck = await Runtime.evaluate({
      expression: `(() => {
        const modal = document.querySelector('.modal-dialog');
        if (!modal) return { open: false };
        const cameraBtn = Array.from(modal.querySelectorAll('button')).find(b => /Ambil foto|Memeriksa/.test(b.textContent));
        const hints = Array.from(modal.querySelectorAll('.ai-upload-hint')).map(h => h.textContent.trim());
        const fileInputs = Array.from(modal.querySelectorAll('input[type="file"]'));
        return {
          open: true,
          cameraBtnText: cameraBtn?.textContent.trim(),
          cameraBtnDisabled: cameraBtn?.disabled,
          hints,
          fileInputsCount: fileInputs.length,
          hasCameraInput: fileInputs.some(i => i.getAttribute('capture') === 'environment'),
        };
      })()`,
      returnByValue: true,
    });
    log('Modal opens', modalCheck.result.value.open);
    if (modalCheck.result.value.open) {
      console.log(`  Camera btn: "${modalCheck.result.value.cameraBtnText}", disabled=${modalCheck.result.value.cameraBtnDisabled}`);
      console.log(`  Hints: ${JSON.stringify(modalCheck.result.value.hints)}`);
      console.log(`  File inputs: ${modalCheck.result.value.fileInputsCount}, has capture="environment": ${modalCheck.result.value.hasCameraInput}`);
      log('Camera button present', !!modalCheck.result.value.cameraBtnText);
      log('Has capture="environment" file input', modalCheck.result.value.hasCameraInput);
      log('Has hint (siap / tidak terdeteksi / meminta izin)',
        modalCheck.result.value.hints.length > 0);
    }

    // Wait for detection to complete
    await new Promise(r => setTimeout(r, 2000));

    const afterDetect = await Runtime.evaluate({
      expression: `(() => {
        const modal = document.querySelector('.modal-dialog');
        if (!modal) return null;
        const cameraBtn = Array.from(modal.querySelectorAll('button')).find(b => /Ambil foto|Memeriksa/.test(b.textContent));
        const hints = Array.from(modal.querySelectorAll('.ai-upload-hint')).map(h => h.textContent.trim());
        // ponytail: spy on file input click
        if (!window.__spyInit) {
          window.__spyInit = true;
          window.__pickerOpens = [];
          const inputs = modal.querySelectorAll('input[type="file"]');
          inputs.forEach((input, i) => {
            const origClick = input.click.bind(input);
            input.click = function() {
              window.__pickerOpens.push({ index: i, capture: input.getAttribute('capture') });
              return origClick();
            };
          });
        }
        return {
          btnText: cameraBtn?.textContent.trim(),
          btnDisabled: cameraBtn?.disabled,
          hints,
        };
      })()`,
      returnByValue: true,
    });
    if (afterDetect.result.value) {
      console.log(`  After detect: btn="${afterDetect.result.value.btnText}", disabled=${afterDetect.result.value.btnDisabled}`);
      console.log(`  Hints: ${JSON.stringify(afterDetect.result.value.hints)}`);
      log('After detect: button shows "Ambil foto"', afterDetect.result.value.btnText.includes('Ambil foto'));
      log('After detect: button NOT disabled', afterDetect.result.value.btnDisabled === false);
      log('After detect: "Kamera siap" hint', afterDetect.result.value.hints.some(h => h.includes('siap')));

      // Click camera button — should open picker
      if (!afterDetect.result.value.btnDisabled) {
        await Runtime.evaluate({
          expression: `(() => { const btn = Array.from(document.querySelectorAll('.modal-dialog button')).find(b => b.textContent.includes('Ambil foto')); if (btn) btn.click(); })()`,
          returnByValue: true,
        });
        await new Promise(r => setTimeout(r, 300));

        const pickerResult = await Runtime.evaluate({
          expression: `JSON.stringify({ pickerOpens: window.__pickerOpens || [] })`,
          returnByValue: true,
        });
        const parsed = JSON.parse(pickerResult.result.value);
        log('Camera button click opens picker', parsed.pickerOpens.length >= 1,
          `opens=${parsed.pickerOpens.length}`);
        if (parsed.pickerOpens.length > 0) {
          log('Picker has capture="environment"', parsed.pickerOpens.some(c => c.capture === 'environment'),
            JSON.stringify(parsed.pickerOpens[0]));
        }
      }
    }

    // Screenshot
    const { data } = await Page.captureScreenshot({ format: 'png' });
    fs.writeFileSync('E:/FTP/Capstone/flashmind/dist/camera-preview.png', Buffer.from(data, 'base64'));
    console.log('\nScreenshot: dist/camera-preview.png');

    console.log(`\n=== Summary ===`);
    console.log(`Passed: ${passed}`);
    console.log(`Failed: ${failed}`);
    await client.close();
    if (failed > 0) process.exit(1);
  } catch (err) {
    console.error('CDP test failed:', err);
    if (client) await client.close();
    process.exit(1);
  }
}

main();
